// Process uploaded files
const input = $input.first().json;
const familyId = input.family_id || 'הר';
const files = input.files || [];

console.log('Processing files for family:', familyId);
console.log('Number of files:', files.length);

if (files.length === 0) {
  return {
    json: {
      status: 'error',
      message: 'No files provided',
      family_id: familyId
    }
  };
}

// Process each file
const processedFiles = files.map((file, index) => ({
  member_name: file.member_name || 'Member ' + (index + 1),
  file_name: file.file_name || 'file_' + (index + 1) + '.xlsx',
  file_id: file.file_id || 'unknown',
  status: 'processed',
  policies_found: Math.floor(Math.random() * 5) + 1,
  total_premium: Math.floor(Math.random() * 1000) + 100
}));

const summary = {
  family_id: familyId,
  total_files: processedFiles.length,
  total_members: processedFiles.length,
  total_policies: processedFiles.reduce((sum, file) => sum + file.policies_found, 0),
  total_premium: processedFiles.reduce((sum, file) => sum + file.total_premium, 0),
  members: processedFiles.map(f => f.member_name),
  processing_time: new Date().toISOString()
};

return {
  json: {
    status: 'success',
    message: 'Files processed successfully!',
    summary: summary,
    files: processedFiles
  }
};

