// Calculate customer health score
const customer = $input.first().json;
const customerStats = $('Get Customer Stats').all().find(stat => stat.json.customer_id === customer.customer_id);
const now = new Date();
const lastActivity = customerStats ? new Date(customerStats.json.timestamp) : new Date(customer.created_at);
const daysSinceActivity = Math.floor((now - lastActivity) / (1000 * 60 * 60 * 24));

// Health score calculation (0-100)
let healthScore = 100;

// Deduct points for inactivity
if (daysSinceActivity > 7) healthScore -= 20;
if (daysSinceActivity > 14) healthScore -= 30;
if (daysSinceActivity > 30) healthScore -= 50;

// Add points for high usage
if (customerStats && customerStats.json.total_time_saved > 20) healthScore += 15;
if (customerStats && customerStats.json.workers_used.split(', ').length >= 3) healthScore += 10;

// Ensure score is between 0-100
healthScore = Math.max(0, Math.min(100, healthScore));

// Determine risk level
let riskLevel = 'low';
if (healthScore < 50) riskLevel = 'high';
else if (healthScore < 75) riskLevel = 'medium';

return {
  customer_id: customer.customer_id,
  email: customer.email,
  name: customer.name,
  plan: customer.plan,
  health_score: healthScore,
  risk_level: riskLevel,
  days_since_activity: daysSinceActivity,
  virtual_workers_used: customerStats ? customerStats.json.workers_used.split(', ').length : 0,
  time_saved_total: customerStats ? customerStats.json.total_time_saved : 0,
  timestamp: new Date().toISOString()
};

// Generate business intelligence report
const allCustomers = $input.all();
const totalCustomers = allCustomers.length;
const highRiskCustomers = allCustomers.filter(c => c.json.risk_level === 'high').length;
const mediumRiskCustomers = allCustomers.filter(c => c.json.risk_level === 'medium').length;
const lowRiskCustomers = allCustomers.filter(c => c.json.risk_level === 'low').length;

const averageHealthScore = Math.round(allCustomers.reduce((sum, c) => sum + c.json.health_score, 0) / totalCustomers);
const totalTimeSaved = allCustomers.reduce((sum, c) => sum + c.json.time_saved_total, 0);

const report = {
  report_date: new Date().toISOString(),
  total_customers: totalCustomers,
  risk_breakdown: {
    high: highRiskCustomers,
    medium: mediumRiskCustomers,
    low: lowRiskCustomers
  },
  average_health_score: averageHealthScore,
  total_time_saved: totalTimeSaved,
  churn_risk_percentage: Math.round((highRiskCustomers / totalCustomers) * 100),
  customer_health_trend: averageHealthScore > 75 ? 'improving' : averageHealthScore > 50 ? 'stable' : 'declining'
};

return report;

