// Fixed MCP Protocol Handler - Correctly accesses webhook body
const input = $input.first();
console.log('MCP Request received:', JSON.stringify(input, null, 2));

// Extract MCP request data from webhook body
const request = input.json.body || input.json;
console.log('Processing request:', JSON.stringify(request, null, 2));

// Extract MCP request data
const jsonrpc = request.jsonrpc || '2.0';
const id = request.id || null;
const method = request.method || '';
const params = request.params || {};

console.log('Method:', method);
console.log('Params:', params);

let response = {
  jsonrpc: jsonrpc,
  id: id,
  result: null,
  error: null
};

switch (method) {
  case 'initialize':
    response.result = {
      protocolVersion: '2024-11-05',
      capabilities: {
        tools: {}
      },
      serverInfo: {
        name: 'Rensto n8n MCP Server',
        version: '1.0.0'
      }
    };
    break;

  case 'tools/list':
    response.result = {
      tools: [
        {
          name: "youtube_search",
          description: "Search YouTube for trending content in specific niches",
          inputSchema: {
            type: "object",
            properties: {
              query: {
                type: "string",
                description: "Search query for YouTube content"
              },
              maxResults: {
                type: "number",
                description: "Maximum number of results to return",
                default: 25
              }
            },
            required: ["query"]
          }
        },
        {
          name: "create_virtual_worker",
          description: "Create a new virtual worker workflow",
          inputSchema: {
            type: "object",
            properties: {
              name: {
                type: "string",
                description: "Virtual worker name"
              },
              industry: {
                type: "string",
                description: "Target industry"
              },
              capabilities: {
                type: "array",
                items: {
                  type: "string"
                },
                description: "List of worker capabilities"
              },
              workflow_type: {
                type: "string",
                enum: ["lead_generation", "content_creation", "customer_service", "billing", "scheduling"],
                description: "Type of workflow to create"
              }
            },
            required: ["name", "industry", "workflow_type"]
          }
        },
        {
          name: "execute_workflow",
          description: "Execute a specific n8n workflow",
          inputSchema: {
            type: "object",
            properties: {
              workflowId: {
                type: "string",
                description: "ID of workflow to execute"
              },
              data: {
                type: "object",
                description: "Data to pass to workflow"
              }
            },
            required: ["workflowId"]
          }
        }
      ]
    };
    break;

  case 'tools/call':
    const toolName = params.name;
    const toolArgs = params.arguments || {};

    console.log('Calling tool:', toolName, 'with args:', toolArgs);

    switch (toolName) {
      case 'youtube_search':
        response.result = {
          content: [
            {
              type: "text",
              text: `Searching YouTube for: "${toolArgs.query}" with max ${toolArgs.maxResults || 25} results`
            }
          ]
        };
        break;

      case 'create_virtual_worker':
        response.result = {
          content: [
            {
              type: "text",
              text: `Created virtual worker: "${toolArgs.name}" for ${toolArgs.industry} industry with ${toolArgs.workflow_type} workflow type`
            }
          ]
        };
        break;

      case 'execute_workflow':
        response.result = {
          content: [
            {
              type: "text",
              text: `Executing workflow: ${toolArgs.workflowId} with data: ${JSON.stringify(toolArgs.data || {})}`
            }
          ]
        };
        break;

      default:
        response.error = {
          code: "tool_not_found",
          message: `Tool '${toolName}' not found`
        };
    }
    break;

  default:
    response.error = {
      code: "method_not_found",
      message: `Method '${method}' not supported`
    };
}

console.log('MCP Response:', JSON.stringify(response, null, 2));

return {
  json: response
};

