// Check if scraping was successful
if (!input.data || !input.data.id) {
  throw new Error(`Apify scraping failed: ${JSON.stringify(input)}`);
}

const runId = input.data.id;
console.log(`Apify run started with ID: ${runId}`);

// Return the run ID and group data for monitoring
return [{
  json: {
    apifyRunId: runId,
    groupName: groupData.groupName,
    groupUrl: groupData.groupUrl,
    memberCount: groupData.memberCount,
    customAudienceName: groupData.customAudienceName,
    status: 'scraping_started',
    timestamp: new Date().toISOString()
  }
}];

// Process scraped Facebook member data
const scrapedData = $input.all();
const groupData = $('Initialize Facebook Groups').first().json;

// Check if we have data
if (!scrapedData || scrapedData.length === 0) {
  console.log('No scraped data available yet, will retry later');
  return [{
    json: {
      groupName: groupData.groupName,
      status: 'no_data_yet',
      message: 'Scraping still in progress',
      timestamp: new Date().toISOString()
    }
  }];
}

// Extract member data from all scraped items
const allMembers = [];
scrapedData.forEach(item => {
  if (item.json && Array.isArray(item.json)) {
    item.json.forEach(member => {
      if (member && member.profileUrl) {
        allMembers.push({
          profileUrl: member.profileUrl,
          name: member.name || '',
          location: member.location || '',
          joinedDate: member.joinedDate || '',
          postsCount: member.postsCount || 0,
          groupName: groupData.groupName,
          scrapedAt: new Date().toISOString()
        });
      }
    });
  }
});

console.log(`Scraped ${allMembers.length} members from ${groupData.groupName}`);

// Filter and clean the data
const validMembers = allMembers.filter(member => {
  return member.profileUrl && 
         member.profileUrl.includes('facebook.com') &&
         member.profileUrl !== 'https://www.facebook.com/';
});

// Remove duplicates based on profile URL
const uniqueMembers = validMembers.filter((member, index, self) =>
  index === self.findIndex(m => m.profileUrl === member.profileUrl)
);

console.log(`Valid unique members: ${uniqueMembers.length}`);

// Prepare data for Facebook Custom Audience
const customAudienceData = {
  groupName: groupData.groupName,
  customAudienceName: groupData.customAudienceName,
  memberCount: uniqueMembers.length,
  members: uniqueMembers.map(member => ({
    profileUrl: member.profileUrl,
    name: member.name,
    location: member.location
  })),
  status: 'data_ready',
  timestamp: new Date().toISOString()
};

return [{
  json: customAudienceData
}];

