    videoId: r.id?.videoId || r.id,
    title: r.snippet?.title || r.title,
    channelTitle: r.snippet?.channelTitle || r.channelTitle,
    publishedAt: r.snippet?.publishedAt || r.publishedAt,
    description: r.snippet?.description || r.description || ''
  }));
  output.push({ json: { items: results, total: results.length } });
}
return output;

const items = $input.all();
const addDays = (d, days) => { const nd = new Date(d); nd.setUTCDate(nd.getUTCDate() + days); return nd; };
return items.map(item => {
  const { title, description = '', targetPlatform = 'YouTube' } = item.json;
  const topic = `${title} — ${targetPlatform}`;
  const notes = `${description || 'No description'}\nPlatform: ${targetPlatform}`;
  const deadline = addDays(new Date(), 7).toISOString();
  return { json: { topic, notes, deadline } };
});

// Process each customer
for (const customer of $input.all()) {
  // Execute Alex Hot Lead (Lead Scoring)
  if (customer.json.plan === 'starter' || customer.json.plan === 'professional' || customer.json.plan === 'enterprise') {
    // Simulate lead scoring automation
    const leadScore = Math.floor(Math.random() * 100) + 1;
    const timeSaved = Math.floor(Math.random() * 5) + 1;

    return {
      customer_id: customer.json.customer_id,
      worker: 'Alex Hot Lead',
      action: 'lead_scoring',
      result: `Scored ${leadScore} leads`, 
      time_saved: timeSaved,
      timestamp: new Date().toISOString()
    };
  }

  return null;
}

// Process each customer
for (const customer of $input.all()) {
  // Execute Jordan Smart Flow (Lead Nurturing)
  if (customer.json.plan === 'starter' || customer.json.plan === 'professional' || customer.json.plan === 'enterprise') {
    // Simulate lead nurturing automation
    const emailsSent = Math.floor(Math.random() * 10) + 1;
    const conversions = Math.floor(Math.random() * 3) + 1;
    const timeSaved = Math.floor(Math.random() * 3) + 1;

    return {
      customer_id: customer.json.customer_id,
      worker: 'Jordan Smart Flow',
      action: 'lead_nurturing',
      result: `Sent ${emailsSent} emails, ${conversions} conversions`,
      time_saved: timeSaved,
      timestamp: new Date().toISOString()
    };
  }

  return null;
}

// Process each customer
for (const customer of $input.all()) {
  // Execute Chris News Sweep (Content)
  if (customer.json.plan === 'starter' || customer.json.plan === 'professional' || customer.json.plan === 'enterprise') {
    // Simulate content aggregation automation
    const articlesFound = Math.floor(Math.random() * 15) + 5;
    const contentCreated = Math.floor(Math.random() * 3) + 1;
    const timeSaved = Math.floor(Math.random() * 2) + 1;

    return {
      customer_id: customer.json.customer_id,
      worker: 'Chris News Sweep',
      action: 'content_aggregation',
      result: `Found ${articlesFound} articles, created ${contentCreated} posts`,
      time_saved: timeSaved,
      timestamp: new Date().toISOString()
    };
  }

  return null;
}

// Calculate total time saved for each customer
const customerStats = {};

for (const execution of $input.all()) {
  const customerId = execution.json.customer_id;

  if (!customerStats[customerId]) {
    customerStats[customerId] = {
      customer_id: customerId,
      total_time_saved: 0,
      total_executions: 0,
      workers_used: new Set()
    };
  }

  customerStats[customerId].total_time_saved += execution.json.time_saved;
  customerStats[customerId].total_executions += 1;
  customerStats[customerId].workers_used.add(execution.json.worker);
}

// Convert to array and format
return Object.values(customerStats).map(stat => ({
  customer_id: stat.customer_id,
  total_time_saved: stat.total_time_saved,
  total_executions: stat.total_executions,
  workers_used: Array.from(stat.workers_used).join(', '),
  timestamp: new Date().toISOString()
}));

// Process the incoming webhook data
const { workerType, data, automationType } = $input.first().json;

// Log the incoming request
console.log('Tax automation webhook received:', { workerType, data, automationType });

// Simulate processing based on worker type
let result = {
  success: true,
  workerType,
  timestamp: new Date().toISOString(),
  message: 'Worker executed successfully'
};

switch (workerType) {
  case 'tax_data_entry':
    result.task = 'OCR processing and data extraction';
    result.status = 'completed';
    result.details = 'Processed tax form data';
    break;

  case 'document_processing':
    result.task = 'Document classification and processing';
    result.status = 'completed';
    result.details = 'Classified invoices and receipts';
    break;

  case 'tax_compliance':
    result.task = 'Compliance checks and form generation';
    result.status = 'completed';
    result.details = 'Prepared K1 forms for submission';
    break;

  case 'client_communication':
    result.task = 'Client reminders and status updates';
    result.status = 'completed';
    result.details = 'Sent tax deadline reminders';
    break;

  default:
    result.task = 'General automation task';
    result.status = 'completed';
    result.details = 'Processed automation request';
}

// Add any additional data from the request
if (data) {
  result.processedData = data;
}

return result;

