console.log('Smart family detection for:', familyId);

// Simulate files in 00_INBOX (in real implementation, this would come from Google Drive)
const filesInFolder = [
  'FAMILY_הר_BATCH_001_MEMBER_01_עמית.xlsx',
  'FAMILY_הר_BATCH_001_MEMBER_02_יונתן.xlsx',
  'FAMILY_הר_BATCH_001_MEMBER_03_אנה.xlsx',
  'FAMILY_הר_BATCH_001_MEMBER_04_אליסה.xlsx',
  'FAMILY_הר_BATCH_001_MEMBER_05_איתן.xlsx',
  'FAMILY_הר_BATCH_001_MANIFEST.json'
];

console.log('Files in folder:', filesInFolder);

// Smart detection logic
const detectionResults = {
  family_id: familyId,
  detection_method: 'smart',
  files_found: filesInFolder.length,
  batch_info: null,
  family_members: [],
  expected_members: 0,
  is_complete: false,
  processing_time: new Date().toISOString()
};

// Method 1: Check for manifest file
const manifestFile = filesInFolder.find(f => f.includes('MANIFEST.json'));
if (manifestFile) {
  console.log('Found manifest file:', manifestFile);

  // Simulate manifest content
  const manifest = {
    family_id: familyId,
    batch_id: "001",
    total_members: 5,
    members: ["עמית", "יונתן", "אנה", "אליסה", "איתן"],
    expected_files: 5
  };

  detectionResults.detection_method = 'manifest';
  detectionResults.batch_info = manifest;
  detectionResults.expected_members = manifest.total_members;
  detectionResults.family_members = manifest.members;

  // Check if all expected files are present
  const memberFiles = filesInFolder.filter(f => f.includes('MEMBER_') && f.includes('.xlsx'));
  detectionResults.is_complete = memberFiles.length >= manifest.expected_files;

  console.log('Manifest detection:', detectionResults);
}

// Method 2: File naming convention detection
if (!detectionResults.is_complete) {
  console.log('Trying file naming convention detection...');

  const batchPattern = new RegExp(`FAMILY_${familyId}_BATCH_(\d+)_MEMBER_(\d+)_([^.]+)\.xlsx`);
  const batches = new Map();

  filesInFolder.forEach(file => {
    const match = file.match(batchPattern);
    if (match) {
      const batchId = match[1];
      const memberNumber = parseInt(match[2]);
      const memberName = match[3];

      if (!batches.has(batchId)) {
        batches.set(batchId, {
          batch_id: batchId,
          members: new Map(),
          max_member_number: 0
        });
      }

      const batch = batches.get(batchId);
      batch.members.set(memberNumber, memberName);
      batch.max_member_number = Math.max(batch.max_member_number, memberNumber);
    }
  });

  if (batches.size > 0) {
    const batchId = Array.from(batches.keys())[0];
    const batch = batches.get(batchId);

    detectionResults.detection_method = 'naming_convention';
    detectionResults.batch_info = {
      batch_id: batchId,
      total_members: batch.max_member_number,
      members: Array.from(batch.members.values())
    };
    detectionResults.expected_members = batch.max_member_number;
    detectionResults.family_members = Array.from(batch.members.values());
    detectionResults.is_complete = batch.members.size >= batch.max_member_number;

    console.log('Naming convention detection:', detectionResults);
  }
}

// Method 3: Simple pattern detection
if (!detectionResults.is_complete) {
  console.log('Trying simple pattern detection...');

  const familyFiles = filesInFolder.filter(f => 
    f.includes(familyId) && f.includes('.xlsx') && !f.includes('MANIFEST')
  );

  if (familyFiles.length >= 2) {
    detectionResults.detection_method = 'simple_pattern';
    detectionResults.expected_members = familyFiles.length;
    detectionResults.family_members = familyFiles.map(f => {
      // Extract name from filename
      const nameMatch = f.match(/([^_]+).xlsx$/);
      return nameMatch ? nameMatch[1] : 'Unknown';
    });
    detectionResults.is_complete = true;

    console.log('Simple pattern detection:', detectionResults);
  }
}

// Force processing if requested
if (forceProcess && detectionResults.family_members.length > 0) {
  detectionResults.is_complete = true;
  detectionResults.detection_method += '_forced';
}

