let estimatedTime = 2;
let requiresHuman = false;

// Complex issues that need human intervention
if (issueType.includes('Billing') || issueType.includes('Payment')) {
  complexity = 'critical';
  estimatedTime = 15;
  requiresHuman = true;
}

// Moderate complexity issues
else if (issueType.includes('Integration') || issueType.includes('Performance')) {
  complexity = 'complex';
  estimatedTime = 8;
  requiresHuman = false;
}

// Simple setup issues
else if (issueType.includes('Setup') || issueType.includes('Import')) {
  complexity = 'simple';
  estimatedTime = 3;
  requiresHuman = false;
}

