// Group projects by status
const projects = $input.all();
const grouped = {};

projects.forEach(project => {
  const status = project.fields.status || 'Unknown';
  if (!grouped[status]) {
    grouped[status] = [];
  }
  grouped[status].push(project);
});

// Create digest HTML
let html = '<h2>🔨 Projects In Progress Digest</h2>';
html += `<p><strong>Total active projects: ${projects.length}</strong></p>`;

Object.keys(grouped).forEach(status => {
  html += `<h3>${status} (${grouped[status].length})</h3>`;
  html += '<ul>';
  grouped[status].forEach(project => {
    html += `<li><strong>${project.fields.project_name || 'Unnamed Project'}</strong>`;
    html += `<br>📅 Due: ${project.fields.due_date || 'Not set'}`;
    html += `<br>👤 Owner: ${project.fields.owner || 'Unassigned'}`;
    html += `<br>💰 Budget: ${project.fields.budget || 'Not set'}`;
    html += `<br>📝 Notes: ${project.fields.notes || 'No notes'}`;
    html += '</li>';
  });
  html += '</ul>';
});

// Create Slack text
let slackText = `## 🔨 Projects In Progress Digest\n\n**Total active projects: ${projects.length}**\n\n`;

Object.keys(grouped).forEach(status => {
  slackText += `**${status} (${grouped[status].length})**\n`;
  grouped[status].forEach(project => {
    slackText += `• **${project.fields.project_name || 'Unnamed Project'}**\n`;
    slackText += `  📅 Due: ${project.fields.due_date || 'Not set'}\n`;
    slackText += `  👤 Owner: ${project.fields.owner || 'Unassigned'}\n`;
    slackText += `  💰 Budget: ${project.fields.budget || 'Not set'}\n`;
  });
  slackText += '\n';
});

return [
  {
    json: {
      html: html,
      slackText: slackText,
      projectCount: projects.length,
      statusGroups: grouped
    }
  }
];

