const userMessage = $input.first().json.message || $input.first().json.text || '';
const lowerMessage = userMessage.toLowerCase();

// Determine which tools to use based on user message
const tools = [];

if (lowerMessage.includes('internet') || lowerMessage.includes('network') || lowerMessage.includes('website')) {
  tools.push('check-networkchuck', 'check-rensto-website');
}

if (lowerMessage.includes('server') || lowerMessage.includes('terry') || lowerMessage.includes('system')) {
  tools.push('check-terry-server', 'check-disk-space');
}

if (lowerMessage.includes('lead') || lowerMessage.includes('prospect') || lowerMessage.includes('customer')) {
  tools.push('analyze-hvac-lead');
}

if (lowerMessage.includes('news') || lowerMessage.includes('industry') || lowerMessage.includes('trend')) {
  tools.push('get-hvac-news', 'analyze-industry-news');
}

if (lowerMessage.includes('health') || lowerMessage.includes('diagnostic') || lowerMessage.includes('status')) {
  tools.push('check-disk-space', 'analyze-system-health');
}

// If no specific tools identified, use all for comprehensive analysis
if (tools.length === 0) {
  tools.push('check-networkchuck', 'check-terry-server', 'check-disk-space', 'check-rensto-website', 'get-hvac-news');
}

return {
  message: userMessage,
  tools: tools,
  timestamp: new Date().toISOString()
};

// Calculate days overdue and categorize urgency
const invoices = $input.all();
const today = new Date();

const categorized = {
  urgent: [],
  overdue: [],
  dueSoon: []
};

invoices.forEach(invoice => {
  const dueDate = new Date(invoice.fields.due_date);
  const daysDiff = Math.floor((today - dueDate) / (1000 * 60 * 60 * 24));

  // Calculate amount
  const amount = parseFloat(invoice.fields.amount) || 0;

  if (daysDiff > 30) {
    categorized.urgent.push({ ...invoice, daysOverdue: daysDiff, amount });
  } else if (daysDiff > 0) {
    categorized.overdue.push({ ...invoice, daysOverdue: daysDiff, amount });
  } else if (daysDiff >= -7) {
    categorized.dueSoon.push({ ...invoice, daysOverdue: daysDiff, amount });
  }
});

// Calculate totals
const totalUrgent = categorized.urgent.reduce((sum, inv) => sum + inv.amount, 0);
const totalOverdue = categorized.overdue.reduce((sum, inv) => sum + inv.amount, 0);
const totalDueSoon = categorized.dueSoon.reduce((sum, inv) => sum + inv.amount, 0);

// Create Slack message
let slackText = '## 📄 Unpaid Invoices Alert\n\n';

if (categorized.urgent.length > 0) {
  slackText += `🚨 **URGENT (${categorized.urgent.length} invoices, $${totalUrgent.toFixed(2)})**\n`;
  categorized.urgent.forEach(invoice => {
    slackText += `• **${invoice.fields.client_name || 'Unknown Client'}** - $${invoice.amount.toFixed(2)}\n`;
    slackText += `  📅 ${invoice.daysOverdue} days overdue\n`;
    slackText += `  📧 ${invoice.fields.client_email || 'No email'}\n`;
  });
  slackText += '\n';
}

if (categorized.overdue.length > 0) {
  slackText += `⚠️ **OVERDUE (${categorized.overdue.length} invoices, $${totalOverdue.toFixed(2)})**\n`;
  categorized.overdue.forEach(invoice => {
    slackText += `• **${invoice.fields.client_name || 'Unknown Client'}** - $${invoice.amount.toFixed(2)}\n`;
    slackText += `  📅 ${invoice.daysOverdue} days overdue\n`;
  });
  slackText += '\n';
}

if (categorized.dueSoon.length > 0) {
  slackText += `📅 **DUE SOON (${categorized.dueSoon.length} invoices, $${totalDueSoon.toFixed(2)})**\n`;
  categorized.dueSoon.forEach(invoice => {
    slackText += `• **${invoice.fields.client_name || 'Unknown Client'}** - $${invoice.amount.toFixed(2)}\n`;
    slackText += `  📅 Due in ${Math.abs(invoice.daysOverdue)} days\n`;
  });
  slackText += '\n';
}

slackText += `**Total Outstanding: $${(totalUrgent + totalOverdue + totalDueSoon).toFixed(2)}**\n\n`;
slackText += '**Action Required:** Follow up with clients and update invoice status in Airtable.';

// Create HTML for email
let html = '<h2>📄 Unpaid Invoices Alert</h2>';

if (categorized.urgent.length > 0) {
  html += `<h3 style="color: #dc2626;">🚨 URGENT (${categorized.urgent.length} invoices, $${totalUrgent.toFixed(2)})</h3>`;
  html += '<ul>';
  categorized.urgent.forEach(invoice => {
    html += `<li><strong>${invoice.fields.client_name || 'Unknown Client'}</strong> - $${invoice.amount.toFixed(2)}<br>`;
    html += `📅 ${invoice.daysOverdue} days overdue<br>`;
    html += `📧 ${invoice.fields.client_email || 'No email'}</li>`;
  });
  html += '</ul>';
}

if (categorized.overdue.length > 0) {
  html += `<h3 style="color: #ea580c;">⚠️ OVERDUE (${categorized.overdue.length} invoices, $${totalOverdue.toFixed(2)})</h3>`;
  html += '<ul>';
  categorized.overdue.forEach(invoice => {
    html += `<li><strong>${invoice.fields.client_name || 'Unknown Client'}</strong> - $${invoice.amount.toFixed(2)}<br>`;
    html += `📅 ${invoice.daysOverdue} days overdue</li>`;
  });
  html += '</ul>';
}

if (categorized.dueSoon.length > 0) {
  html += `<h3 style="color: #ca8a04;">📅 DUE SOON (${categorized.dueSoon.length} invoices, $${totalDueSoon.toFixed(2)})</h3>`;
  html += '<ul>';
  categorized.dueSoon.forEach(invoice => {
    html += `<li><strong>${invoice.fields.client_name || 'Unknown Client'}</strong> - $${invoice.amount.toFixed(2)}<br>`;
    html += `📅 Due in ${Math.abs(invoice.daysOverdue)} days</li>`;
  });
  html += '</ul>';
}

html += `<p><strong>Total Outstanding: $${(totalUrgent + totalOverdue + totalDueSoon).toFixed(2)}</strong></p>`;
html += '<p><strong>Action Required:</strong> Follow up with clients and update invoice status in Airtable.</p>';

return [
  {
    json: {
      slackText: slackText,
      html: html,
      categorized: categorized,
      totals: {
        urgent: totalUrgent,
        overdue: totalOverdue,
        dueSoon: totalDueSoon,
        total: totalUrgent + totalOverdue + totalDueSoon
      }
    }
  }
];

// Execute Alex Hot Lead (Lead Scoring)
const customer = $input.first().json;

if (customer.plan === 'starter' || customer.plan === 'professional' || customer.plan === 'enterprise') {
  // Simulate lead scoring automation
  const leadScore = Math.floor(Math.random() * 100) + 1;
  const timeSaved = Math.floor(Math.random() * 5) + 1;

  return {
    customer_id: customer.customer_id,
    customer_email: customer.email,
    customer_name: customer.name,
    customer_plan: customer.plan,
    worker: 'Alex Hot Lead',
    action: 'lead_scoring',
    result: `Scored ${leadScore} leads`,
    time_saved: timeSaved,
    timestamp: new Date().toISOString()
  };
}

return null;

// Execute Jordan Smart Flow (Lead Nurturing)
const customer = $input.first().json;

if (customer.plan === 'starter' || customer.plan === 'professional' || customer.plan === 'enterprise') {
  // Simulate lead nurturing automation
  const emailsSent = Math.floor(Math.random() * 10) + 1;
  const conversions = Math.floor(Math.random() * 3) + 1;
  const timeSaved = Math.floor(Math.random() * 3) + 1;

  return {
    customer_id: customer.customer_id,
    customer_email: customer.email,
    customer_name: customer.name,
    customer_plan: customer.plan,
    worker: 'Jordan Smart Flow',
    action: 'lead_nurturing',
    result: `Sent ${emailsSent} emails, ${conversions} conversions`,
    time_saved: timeSaved,
    timestamp: new Date().toISOString()
  };
}

return null;

// Execute Chris News Sweep (Content)
const customer = $input.first().json;

if (customer.plan === 'starter' || customer.plan === 'professional' || customer.plan === 'enterprise') {
  // Simulate content aggregation automation
  const articlesFound = Math.floor(Math.random() * 15) + 5;
  const contentCreated = Math.floor(Math.random() * 3) + 1;
  const timeSaved = Math.floor(Math.random() * 2) + 1;

  return {
    customer_id: customer.customer_id,
    customer_email: customer.email,
    customer_name: customer.name,
    customer_plan: customer.plan,
    worker: 'Chris News Sweep',
    action: 'content_aggregation',
    result: `Found ${articlesFound} articles, created ${contentCreated} posts`,
    time_saved: timeSaved,
    timestamp: new Date().toISOString()
  };
}

return null;

// Calculate total time saved for each customer
const customerStats = {};

for (const execution of $input.all()) {
  const customerId = execution.json.customer_id;

  if (!customerStats[customerId]) {
    customerStats[customerId] = {
      customer_id: customerId,
      customer_email: execution.json.customer_email,
      customer_name: execution.json.customer_name,
      total_time_saved: 0,
      total_executions: 0,
      workers_used: new Set()
    };
  }

  customerStats[customerId].total_time_saved += execution.json.time_saved;
  customerStats[customerId].total_executions += 1;
  customerStats[customerId].workers_used.add(execution.json.worker);
}

// Convert to array and format
return Object.values(customerStats).map(stat => ({
  customer_id: stat.customer_id,
  customer_email: stat.customer_email,
  customer_name: stat.customer_name,
  total_time_saved: stat.total_time_saved,
  total_executions: stat.total_executions,
  workers_used: Array.from(stat.workers_used).join(', '),
  timestamp: new Date().toISOString()
}));

