// Proper MCP Protocol Handler
const request = $input.first().json;
console.log('MCP Request received:', JSON.stringify(request, null, 2));

// Extract MCP request data
const jsonrpc = request.jsonrpc || '2.0';
const id = request.id || null;
const method = request.method || '';
const params = request.params || {};

let response = {
  jsonrpc: jsonrpc,
  id: id,
  result: null,
  error: null
};

console.log('Processing method:', method);

switch (method) {
  case 'initialize':
    response.result = {
      protocolVersion: '2024-11-05',
      capabilities: {
        tools: {}
      },
      serverInfo: {
        name: 'Rensto n8n MCP Server',
        version: '1.0.0'
      }
    };
    break;

  case 'tools/list':
    response.result = {
      tools: [
        {
          name: "youtube_search",
          description: "Search YouTube for trending content in specific niches",
          inputSchema: {
            type: "object",
            properties: {
              query: {
                type: "string",
                description: "Search query for YouTube content"
              },
              maxResults: {
                type: "number",
                description: "Maximum number of results to return",
                default: 25
              }
            },
            required: ["query"]
          }
        },
        {
          name: "create_virtual_worker",
          description: "Create a new virtual worker workflow",
          inputSchema: {
            type: "object",
            properties: {
              name: {
                type: "string",
                description: "Virtual worker name"
              },
              industry: {
                type: "string",
                description: "Target industry"
              },
              capabilities: {
                type: "array",
                items: {
                  type: "string"
                },
                description: "List of worker capabilities"
              },
              workflow_type: {
                type: "string",
                enum: ["lead_generation", "content_creation", "customer_service", "billing", "scheduling"],
                description: "Type of workflow to create"
              }
            },
            required: ["name", "industry", "workflow_type"]
          }
        },
        {
          name: "execute_workflow",
          description: "Execute a specific n8n workflow",
          inputSchema: {
            type: "object",
            properties: {
              workflowId: {
                type: "string",
                description: "ID of workflow to execute"
              },
              data: {
                type: "object",
                description: "Data to pass to workflow"
              }
            },
            required: ["workflowId"]
          }
        }
      ]
    };
    break;

  case 'tools/call':
    const toolName = params.name;
    const toolArgs = params.arguments || {};

    console.log('Calling tool:', toolName, 'with args:', toolArgs);

    switch (toolName) {
      case 'youtube_search':
        response.result = {
          content: [
            {
              type: "text",
              text: `Searching YouTube for: "${toolArgs.query}" with max ${toolArgs.maxResults || 25} results`
            }
          ]
        };
        break;

      case 'create_virtual_worker':
        response.result = {
          content: [
            {
              type: "text",
              text: `Created virtual worker: "${toolArgs.name}" for ${toolArgs.industry} industry with ${toolArgs.workflow_type} workflow type`
            }
          ]
        };
        break;

      case 'execute_workflow':
        response.result = {
          content: [
            {
              type: "text",
              text: `Executing workflow: ${toolArgs.workflowId} with data: ${JSON.stringify(toolArgs.data || {})}`
            }
          ]
        };
        break;

      default:
        response.error = {
          code: "tool_not_found",
          message: `Tool '${toolName}' not found`
        };
    }
    break;

  default:
    response.error = {
      code: "method_not_found",
      message: `Method '${method}' not supported`
    };
}

console.log('MCP Response:', JSON.stringify(response, null, 2));

return {
  json: response
};

// Categorize assets by criticality and days to renewal
const assets = $input.all();
const today = new Date();

const categorized = {
  critical: [],
  important: [],
  standard: []
};

assets.forEach(asset => {
  const renewalDate = new Date(asset.fields.renewal_date);
  const daysToRenewal = Math.floor((renewalDate - today) / (1000 * 60 * 60 * 24));
  const cost = parseFloat(asset.fields.monthly_cost) || 0;
  const criticality = asset.fields.criticality || 'standard';

  const enrichedAsset = {
    ...asset,
    daysToRenewal,
    cost,
    criticality
  };

  if (criticality === 'critical' || daysToRenewal <= 7) {
    categorized.critical.push(enrichedAsset);
  } else if (criticality === 'important' || daysToRenewal <= 14) {
    categorized.important.push(enrichedAsset);
  } else {
    categorized.standard.push(enrichedAsset);
  }
});

// Calculate totals
const totalCritical = categorized.critical.reduce((sum, asset) => sum + asset.cost, 0);
const totalImportant = categorized.important.reduce((sum, asset) => sum + asset.cost, 0);
const totalStandard = categorized.standard.reduce((sum, asset) => sum + asset.cost, 0);

// Create Slack message
let slackText = '## 🔄 Assets Renewing Soon (< 30 days)\n\n';

if (categorized.critical.length > 0) {
  slackText += `🚨 **CRITICAL (${categorized.critical.length} assets, $${totalCritical.toFixed(2)}/month)**\n`;
  categorized.critical.forEach(asset => {
    slackText += `• **${asset.fields.asset_name || 'Unnamed Asset'}** - $${asset.cost.toFixed(2)}/month\n`;
    slackText += `  📅 Renews in ${asset.daysToRenewal} days\n`;
    slackText += `  👤 Owner: ${asset.fields.owner || 'Unassigned'}\n`;
    slackText += `  🔗 Provider: ${asset.fields.provider || 'Unknown'}\n`;
  });
  slackText += '\n';
}

if (categorized.important.length > 0) {
  slackText += `⚠️ **IMPORTANT (${categorized.important.length} assets, $${totalImportant.toFixed(2)}/month)**\n`;
  categorized.important.forEach(asset => {
    slackText += `• **${asset.fields.asset_name || 'Unnamed Asset'}** - $${asset.cost.toFixed(2)}/month\n`;
    slackText += `  📅 Renews in ${asset.daysToRenewal} days\n`;
    slackText += `  👤 Owner: ${asset.fields.owner || 'Unassigned'}\n`;
  });
  slackText += '\n';
}

if (categorized.standard.length > 0) {
  slackText += `📅 **STANDARD (${categorized.standard.length} assets, $${totalStandard.toFixed(2)}/month)**\n`;
  categorized.standard.forEach(asset => {
    slackText += `• **${asset.fields.asset_name || 'Unnamed Asset'}** - $${asset.cost.toFixed(2)}/month\n`;
    slackText += `  📅 Renews in ${asset.daysToRenewal} days\n`;
  });
  slackText += '\n';
}

slackText += `**Total Monthly Cost: $${(totalCritical + totalImportant + totalStandard).toFixed(2)}**\n\n`;
slackText += '**Action Required:** Review renewal decisions and update asset status in Airtable.';

// Create HTML for email
let html = '<h2>🔄 Assets Renewing Soon (< 30 days)</h2>';

if (categorized.critical.length > 0) {
  html += `<h3 style="color: #dc2626;">🚨 CRITICAL (${categorized.critical.length} assets, $${totalCritical.toFixed(2)}/month)</h3>`;
  html += '<ul>';
  categorized.critical.forEach(asset => {
    html += `<li><strong>${asset.fields.asset_name || 'Unnamed Asset'}</strong> - $${asset.cost.toFixed(2)}/month<br>`;
    html += `📅 Renews in ${asset.daysToRenewal} days<br>`;
    html += `👤 Owner: ${asset.fields.owner || 'Unassigned'}<br>`;
    html += `🔗 Provider: ${asset.fields.provider || 'Unknown'}</li>`;
  });
  html += '</ul>';
}

if (categorized.important.length > 0) {
  html += `<h3 style="color: #ea580c;">⚠️ IMPORTANT (${categorized.important.length} assets, $${totalImportant.toFixed(2)}/month)</h3>`;
  html += '<ul>';
  categorized.important.forEach(asset => {
    html += `<li><strong>${asset.fields.asset_name || 'Unnamed Asset'}</strong> - $${asset.cost.toFixed(2)}/month<br>`;
    html += `📅 Renews in ${asset.daysToRenewal} days<br>`;
    html += `👤 Owner: ${asset.fields.owner || 'Unassigned'}</li>`;
  });
  html += '</ul>';
}

if (categorized.standard.length > 0) {
  html += `<h3 style="color: #ca8a04;">📅 STANDARD (${categorized.standard.length} assets, $${totalStandard.toFixed(2)}/month)</h3>`;
  html += '<ul>';
  categorized.standard.forEach(asset => {
    html += `<li><strong>${asset.fields.asset_name || 'Unnamed Asset'}</strong> - $${asset.cost.toFixed(2)}/month<br>`;
    html += `📅 Renews in ${asset.daysToRenewal} days</li>`;
  });
  html += '</ul>';
}

html += `<p><strong>Total Monthly Cost: $${(totalCritical + totalImportant + totalStandard).toFixed(2)}</strong></p>`;
html += '<p><strong>Action Required:</strong> Review renewal decisions and update asset status in Airtable.</p>';

return [
  {
    json: {
      slackText: slackText,
      html: html,
      categorized: categorized,
      totals: {
        critical: totalCritical,
        important: totalImportant,
        standard: totalStandard,
        total: totalCritical + totalImportant + totalStandard
      }
    }
  }
];

